export function runMigrations(db: Database): void {
  // 1. Ensure tracking table
  db.run(`CREATE TABLE IF NOT EXISTS _migrations (...)`);

  // 2. Load .sql files from migrations directory, sorted
  const files = readdirSync(migrationsDir).filter(f => f.endsWith(".sql")).sort();
  const migrations = files.map(file => ({
    version: parseInt(file.split("_")[0]),
    name: file.replace(".sql", ""),
    sql: readFileSync(join(migrationsDir, file), "utf-8"),
    checksum: createHash("sha256").update(sql).digest("hex"),
  }));

  // 3. Get already-applied migrations from _migrations table
  // 4. Bootstrap: if pre-migration DB exists, mark 001 as applied
  // 5. Apply pending migrations in transactions
  for (const migration of migrations) {
    if (existing) { /* verify checksum, skip */ continue; }
    db.transaction(() => {
      db.exec(migration.sql);
      db.run("INSERT INTO _migrations ...", [...]);
    })();
  }
}
